```python
class ErrorSource(BaseModel):
    """The source of the error in the request, either in the request body or a query parameter"""

    parameter: Optional[str] = Field(
        None, description="Which query parameter caused the issue, such as an invalid page size"
    )
    pointer: Optional[str] = Field(
        None,
        description="Which part of the request body caused the error, expressed as a JSON Pointer([RFC6901](https://tools.ietf.org/html/rfc6901)) (examples - '/' for the primary data object or '/attributes/title' to indicate a problem with the 'title' field)",
    )


class Error(BaseModel):
    """Information about an error that occurred"""

    title: str = Field(
        description="Human readable description of what went wrong, can be localized (example: 'Validation Error')"
    )
    status: str = Field(
        description="HTTP Status code describing the problem (example: '503' or '400')"
    )
    code: Optional[str] = Field(
        None,
        description="Similar to 'title' in describing the general error but in machine-readable form (example: 'validation_error')",
    )
    detail: Optional[str] = Field(
        None,
        description="Human readable description specific to this occurrence, can be localized (example: 'Start time cannot be after end time')",
    )
    source: Optional[ErrorSource] = Field(
        None, description="Which part of the request the error occurred"
    )
    meta: Optional[Any] = Field(
        None, description="Contains non-standard meta-information about the error"
    )


class ErrorResponse(BaseModel):
    errors: List[Error] = Field(..., description="What went wrong in the request")

def custom_openapi():


    if app.openapi_schema:
        return app.openapi_schema
    openapi_schema = get_openapi(
        title="Custom title",
        version="2.5.0",
        description="This is a very custom OpenAPI schema",
        routes=app.routes,
    )

    # not quite the ideal scenario but this is the best we can do to override the default
    # error schema. See
    from fastapi.openapi.constants import REF_PREFIX
    import pydantic.schema
    
    paths = openapi_schema["paths"]
    for path in paths:
        for method in paths[path]:
            if paths[path][method]["responses"].get("422"):
                paths[path][method]["responses"]["400"] = {
                    "description": "Validation Error",
                    "content": {
                        "application/json": {"schema": {"$ref": f"{REF_PREFIX}ErrorResponse"}}
                    },
                }
                paths[path][method]["responses"].pop("422")

    error_response_defs = pydantic.schema.schema(
        (ErrorResponse,), ref_prefix=REF_PREFIX, ref_template=f"{REF_PREFIX}{{model}}"
    )
    openapi_schemas = openapi_schema["components"]["schemas"]
    openapi_schemas.update(error_response_defs["definitions"])
    openapi_schemas.pop("ValidationError")
    openapi_schemas.pop("HTTPValidationError")

    app.openapi_schema = openapi_schema
